//! MFASetup flow implementation
//!
//! Generated by metaphor-schema
//!
//! MFA device enrollment process including:
//! - Device type selection
//! - Secret generation (TOTP) or phone verification (SMS)
//! - Initial code verification
//! - Backup codes generation
//! - User notification

use serde::{Deserialize, Serialize};
use std::sync::Arc;
use chrono;
use backbone_core::flow::{WorkflowStep, WorkflowContext};

/// Error type for flow execution
#[derive(Debug, Clone, thiserror::Error)]
pub enum FlowError {
    #[error("No current step to execute")]
    NoCurrentStep,

    #[error("Step execution failed: {0}")]
    StepFailed(String),

    #[error("Condition evaluation failed: {0}")]
    ConditionFailed(String),

    #[error("Compensation failed: {0}")]
    CompensationFailed(String),

    #[error("Flow timed out")]
    Timeout,

    #[error("Flow cancelled")]
    Cancelled,

    #[error("Invalid state transition: {from} -> {to}")]
    InvalidTransition { from: String, to: String },
}

/// Execution status for MFASetup flow
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MFASetupFlowStatus {
    /// Flow is pending execution
    Pending,
    /// Flow is currently running
    Running,
    /// Flow is waiting for an event or condition
    Waiting,
    /// Flow completed successfully
    Completed,
    /// Flow failed
    Failed,
    /// Flow was cancelled
    Cancelled,
    /// Flow is compensating (rolling back)
    Compensating,
}

/// Steps in MFASetup flow
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MFASetupFlowStep {
    /// validate_user
    ValidateUser,
    /// check_existing_device
    CheckExistingDevice,
    /// check_can_add
    CheckCanAdd,
    /// route_by_type
    RouteByType,
    /// generate_totp_secret
    GenerateTotpSecret,
    /// create_totp_device
    CreateTotpDevice,
    /// wait_totp_verification
    WaitTotpVerification,
    /// verify_phone_number
    VerifyPhoneNumber,
    /// create_sms_device
    CreateSmsDevice,
    /// wait_sms_verification
    WaitSmsVerification,
    /// activate_device
    ActivateDevice,
    /// generate_backup_codes
    GenerateBackupCodes,
    /// create_backup_device
    CreateBackupDevice,
    /// enable_mfa_on_user_settings
    EnableMfaOnUserSettings,
    /// send_mfa_enabled_email
    SendMfaEnabledEmail,
    /// log_mfa_setup
    LogMfaSetup,
    /// complete
    Complete,
    /// error_existing_totp
    ErrorExistingTotp,
    /// error_end
    ErrorEnd,
    /// setup_timeout
    SetupTimeout,
    /// log_timeout
    LogTimeout,
    /// timeout_end
    TimeoutEnd,
}

/// Instance of MFASetup flow execution
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MFASetupFlowInstance {
    /// Unique instance ID
    pub id: String,
    /// Current status
    pub status: MFASetupFlowStatus,
    /// Current step
    pub current_step: Option<MFASetupFlowStep>,
    /// Flow context (variables)
    pub context: serde_json::Value,
    /// Completed steps
    pub completed_steps: Vec<MFASetupFlowStep>,
    /// Error if failed
    pub error: Option<String>,
    /// Created timestamp
    pub created_at: chrono::DateTime<chrono::Utc>,
    /// Updated timestamp
    pub updated_at: chrono::DateTime<chrono::Utc>,
}

impl MFASetupFlowInstance {
    /// Create a new flow instance
    pub fn new(id: impl Into<String>) -> Self {
        let now = chrono::Utc::now();
        Self {
            id: id.into(),
            status: MFASetupFlowStatus::Pending,
            current_step: None,
            context: serde_json::json!({}),
            completed_steps: Vec::new(),
            error: None,
            created_at: now,
            updated_at: now,
        }
    }

    /// Check if flow is complete
    pub fn is_complete(&self) -> bool {
        matches!(
            self.status,
            MFASetupFlowStatus::Completed | MFASetupFlowStatus::Failed | MFASetupFlowStatus::Cancelled
        )
    }

    /// Check if flow is running
    pub fn is_running(&self) -> bool {
        matches!(
            self.status,
            MFASetupFlowStatus::Running | MFASetupFlowStatus::Waiting
        )
    }

    /// Set a context variable
    pub fn set_context(&mut self, key: &str, value: serde_json::Value) {
        if let serde_json::Value::Object(ref mut map) = self.context {
            map.insert(key.to_string(), value);
        }
        self.updated_at = chrono::Utc::now();
    }

    /// Get a context variable
    pub fn get_context(&self, key: &str) -> Option<&serde_json::Value> {
        if let serde_json::Value::Object(ref map) = self.context {
            map.get(key)
        } else {
            None
        }
    }
}

// Phase 1: FlowInstance satisfies backbone_core::flow::WorkflowContext.
// The entity() accessor requires the entity to be carried in the instance;
// add `pub entity: MFASetup` in the // <<< CUSTOM section and remove the todo!.
#[allow(unused_variables)]
impl WorkflowContext<MFASetupFlowInstance> for MFASetupFlowInstance {
    fn entity(&self) -> &MFASetupFlowInstance { self }
    fn set_var(&mut self, key: &str, value: serde_json::Value) {
        self.set_context(key, value);
    }
    fn get_var(&self, key: &str) -> Option<&serde_json::Value> {
        self.get_context(key)
    }
}

